roadmaps.roadmap:
{
  "roadmap_title": "Cracking FAANG Technical Interviews in 3 Months",
  "duration": "3 Months",
  "phases": [
    {
      "phase_title": "Phase 1: Data Structures and Algorithms Fundamentals",
      "description": "Mastering essential data structures and algorithms to crack technical interviews",
      "core_topics": [
        "Arrays and Linked Lists",
        "Stacks and Queues",
        "Trees (BST, AVL, etc.)",
        "Graphs (Basic, DFS, BFS)",
        "Bit Manipulation",
        "Recursion and Backtracking"
      ]
    },
    {
      "phase_title": "Phase 2: Coding Challenges and Problem-Solving Strategies",
      "description": "Developing strategies to tackle complex coding challenges and practice problem-solving",
      "core_topics": [
        "LeetCode, HackerRank, and other popular platforms",
        "System Design and Scalability",
        "Common Interview Patterns and Tricks",
        "Practice with Mock Interviews and Feedback",
        "Time and Space Complexity Analysis"
      ]
    },
    {
      "phase_title": "Phase 3: Advanced Topics and Specialized Skills",
      "description": "Mastering advanced topics and specialized skills to become a top candidate",
      "core_topics": [
        "Dynamic Programming (Memoization, Tabulation, etc.)",
        "Greedy Algorithms and Divide and Conquer",
        "Advanced Data Structures (Heaps, Trie, etc.)",
        "Database Systems and SQL",
        "Operating System Fundamentals"
      ]
    },
    {
      "phase_title": "Phase 4: Final Preparation and Mock Interviews",
      "description": "Final preparation and practice to crack FAANG technical interviews",
      "core_topics": [
        "Review and Practice of All Core Topics",
        "Mock Interviews and Feedback Session",
        "Common Interview Questions and Patterns",
        "Final Preparation and Confidence Building"
      ]
    }
  ]
}
